const email = $input.item.json;

// Get email details - Gmail structure is different
const from = email.From || '';
const subject = email.Subject || '';
const snippet = email.snippet || ''; // Gmail provides snippet with email preview
const threadId = email.threadId;

// Extract email address from "Name <email@domain.com>" format
const emailMatch = from.match(/<(.+?)>/);
const fromEmail = emailMatch ? emailMatch[1] : from;

// Check if it's a reply (subject starts with "Re:")
const isReply = subject.toLowerCase().startsWith('re:');

// Check if subject matches your coaching emails
const isCoachingThread = subject.toLowerCase().includes('schedule') || 
                          subject.toLowerCase().includes('coaching') || 
                          subject.toLowerCase().includes('calendar') ||
                          subject.toLowerCase().includes('leadership') ||
                          subject.toLowerCase().includes('resources');

// Check for time/date keywords in snippet (Gmail's text preview)
const timeKeywords = [
  'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 
  'saturday', 'sunday', 'am', 'pm', 'morning', 'afternoon',
  'slot 1', 'slot 2', 'slot 3', 'slot 4', 'slot 5', 'slot 6',
  'first option', 'second option', 'works for me', 'available',
  'feb', 'january', 'february', 'march', 'april', 'may', 'june',
  'july', 'august', 'september', 'october', 'november', 'december',
  '5:00', '6:00', '7:00', '8:00', '9:00', '10:00', '11:00', '12:00',
  '1:00', '2:00', '3:00', '4:00'
];

const containsTimeReference = timeKeywords.some(keyword => 
  snippet.toLowerCase().includes(keyword)
);

// Pass through if it matches criteria
if (isReply && isCoachingThread && containsTimeReference) {
  return [{
    json: {
      from: fromEmail,
      fromFull: from,
      subject: subject,
      snippet: snippet,
      threadId: threadId,
      receivedAt: new Date().toISOString(),
      isValidResponse: true
    }
  }];
}

// Stop workflow if doesn't match
return [];

// Get snippet and subject
const snippet = $input.item.json.snippet || '';
const subject = $input.item.json.subject || '';

// ===== STEP 1: Extract only the NEW part of the reply (before quoted text) =====
let cleanSnippet = snippet;

// Common patterns that indicate start of quoted text
const quotePatterns = [
  /On\s+\w+,\s+\d+\s+\w+\s+\d{4}\s+at\s+\d+:\d+/i,  // "On Tue, 3 Feb 2026 at 07:32"
  /On\s+\d+\/\d+\/\d+/i,                              // "On 02/03/2026"
  /-{3,}\s*Original Message\s*-{3,}/i,                // "--- Original Message ---"
  /_{3,}/,                                             // "___________"
  /From:\s*</i,                                        // Email headers
  />\s*wrote:/i,                                       // "> wrote:"
  /&lt;.*?&gt;\s*wrote:/i                             // HTML encoded "wrote:"
];

// Find where quoted text starts and cut it off
for (const pattern of quotePatterns) {
  const match = snippet.match(pattern);
  if (match) {
    cleanSnippet = snippet.substring(0, match.index).trim();
    break;
  }
}

// Use cleanSnippet instead of full snippet for processing
const emailText = (cleanSnippet + ' ' + subject).toLowerCase();

// ===== STEP 2: Initialize result object =====
let result = {
  date: null,
  time: null,
  timezone: 'EST',
  needs_clarification: false,
  raw_text: emailText,
  clean_snippet: cleanSnippet
};

// ===== STEP 3: Day of week mapping =====
const daysOfWeek = {
  'monday': 1,
  'tuesday': 2,
  'wednesday': 3,
  'thursday': 4,
  'friday': 5,
  'saturday': 6,
  'sunday': 0
};

// ===== STEP 4: Month mapping =====
const months = {
  'jan': 0, 'january': 0,
  'feb': 1, 'february': 1,
  'mar': 2, 'march': 2,
  'apr': 3, 'april': 3,
  'may': 4,
  'jun': 5, 'june': 5,
  'jul': 6, 'july': 6,
  'aug': 7, 'august': 7,
  'sep': 8, 'sept': 8, 'september': 8,
  'oct': 9, 'october': 9,
  'nov': 10, 'november': 10,
  'dec': 11, 'december': 11
};

// ===== STEP 5: Extract Date =====

// Pattern 1: "monday feb 2" or "monday february 2"
const datePattern1 = /(?:monday|tuesday|wednesday|thursday|friday|saturday|sunday)\s+(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec|january|february|march|april|june|july|august|september|october|november|december)\s*(\d{1,2})/i;
const match1 = emailText.match(datePattern1);

if (match1) {
  const month = months[match1[1].toLowerCase()];
  const day = parseInt(match1[2]);
  const year = new Date().getFullYear();

  // Create date
  let extractedDate = new Date(year, month, day);

  // IMPROVED: Only go to next year if more than 7 days in past
  const today = new Date();
  const diffDays = (today - extractedDate) / (1000 * 60 * 60 * 24);

  if (diffDays > 7) {
    extractedDate.setFullYear(year + 1);
  } else if (diffDays > 0 && diffDays <= 7) {
    // If within past week, check if day of week matches
    const dayName = match1[0].split(' ')[0].toLowerCase();
    const expectedDayNum = daysOfWeek[dayName];

    if (extractedDate.getDay() !== expectedDayNum) {
      // Day doesn't match - find next occurrence
      const currentDay = today.getDay();
      let daysUntil = expectedDayNum - currentDay;
      if (daysUntil <= 0) daysUntil += 7;

      extractedDate = new Date(today);
      extractedDate.setDate(today.getDate() + daysUntil);
    } else {
      // Day matches but date is in past - assume next week
      extractedDate.setDate(extractedDate.getDate() + 7);
    }
  }

  result.date = extractedDate.toISOString().split('T')[0];
}

// Pattern 2: "feb 2", "february 2" (without day of week)
const datePattern2 = /(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec|january|february|march|april|june|july|august|september|october|november|december)\s*(\d{1,2})/i;
const match2 = !match1 && emailText.match(datePattern2);

if (match2) {
  const month = months[match2[1].toLowerCase()];
  const day = parseInt(match2[2]);
  const year = new Date().getFullYear();

  let extractedDate = new Date(year, month, day);
  const today = new Date();
  const diffDays = (today - extractedDate) / (1000 * 60 * 60 * 24);

  // More lenient - only bump year if more than 30 days in past
  if (diffDays > 30) {
    extractedDate.setFullYear(year + 1);
  }

  result.date = extractedDate.toISOString().split('T')[0];
}

// Pattern 3: Numeric date "2/5" or "02/05/2026"
const datePattern3 = /(\d{1,2})\/(\d{1,2})(?:\/(\d{2,4}))?/;
const match3 = !match1 && !match2 && emailText.match(datePattern3);

if (match3) {
  const month = parseInt(match3[1]) - 1;
  const day = parseInt(match3[2]);
  const year = match3[3] ? (match3[3].length === 2 ? 2000 + parseInt(match3[3]) : parseInt(match3[3])) : new Date().getFullYear();

  const extractedDate = new Date(year, month, day);
  result.date = extractedDate.toISOString().split('T')[0];
}

// Pattern 4: Day of week only (e.g., "monday")
if (!result.date) {
  for (const [day, dayNum] of Object.entries(daysOfWeek)) {
    if (emailText.includes(day)) {
      const today = new Date();
      const currentDay = today.getDay();
      let daysUntil = dayNum - currentDay;
      if (daysUntil <= 0) daysUntil += 7;

      const targetDate = new Date(today);
      targetDate.setDate(today.getDate() + daysUntil);
      result.date = targetDate.toISOString().split('T')[0];
      break;
    }
  }
}

// ===== STEP 6: Extract Time =====

// Pattern 1: "5:00 am", "5:00am", "6:00 am"
const timePattern1 = /(\d{1,2}):?(\d{2})?\s*(am|pm)/i;
const timeMatch1 = emailText.match(timePattern1);

if (timeMatch1) {
  let hours = parseInt(timeMatch1[1]);
  const minutes = timeMatch1[2] ? parseInt(timeMatch1[2]) : 0;
  const meridiem = timeMatch1[3].toLowerCase();

  // Convert to 24-hour format
  if (meridiem === 'pm' && hours !== 12) hours += 12;
  if (meridiem === 'am' && hours === 12) hours = 0;

  result.time = `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}`;
}

// Pattern 2: "slot 1", "slot 2", etc.
const slotMatch = emailText.match(/slot\s*(\d)/);
if (slotMatch && !result.time) {
  result.selected_slot = parseInt(slotMatch[1]);
}

// Pattern 3: "first option", "second option"
const optionWords = ['first', 'second', 'third', 'fourth', 'fifth', 'sixth'];
for (let i = 0; i < optionWords.length; i++) {
  if (emailText.includes(optionWords[i] + ' option')) {
    result.selected_slot = i + 1;
    break;
  }
}

// ===== STEP 7: Validation =====

// Check if we have both date and time (or slot)
if (!result.date || (!result.time && !result.selected_slot)) {
  result.needs_clarification = true;
}

// Validate date is in the future (allow up to 2 days in past for tolerance)
if (result.date) {
  const extractedDate = new Date(result.date);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const diffDays = (today - extractedDate) / (1000 * 60 * 60 * 24);

  if (diffDays > 2) {
    result.needs_clarification = true;
    result.clarification_reason = 'Date appears to be in the past';
  }
}

// ===== STEP 8: Return result =====
return [{
  json: {
    ...$input.item.json,
    extracted: result
  }
}];

const inputData = $input.item.json;
const startDateTime = new Date(inputData.extracted.date + 'T' + inputData.extracted.time + ':00');
const endDateTime = new Date(startDateTime);
endDateTime.setMinutes(endDateTime.getMinutes() + 30);

return [{
  json: {
    ...inputData,
    calendar_query: {
      start: startDateTime.toISOString(),
      end: endDateTime.toISOString()
    }
  }
}];

const inputData = $input.item.json;
const extractedDateTime = inputData.extracted;

// Lead's requested time is in EST (UTC-5)
// Parse the date and time as EST
const requestedDateStr = extractedDateTime.date; // "2026-02-09"
const requestedTimeStr = extractedDateTime.time; // "06:00"

// SAFE CHECK: Make sure time exists
if (!requestedTimeStr) {
  throw new Error('No time found in extracted data');
}

// Create date in EST (America/New_York timezone)
// EST is UTC-5, so 6:00 AM EST = 11:00 AM UTC
const [hours, minutes] = requestedTimeStr.split(':');

// Parse as ISO string and convert to UTC
const requestedStartEST = new Date(`${requestedDateStr}T${requestedTimeStr}:00-05:00`);
const requestedEndEST = new Date(requestedStartEST);
requestedEndEST.setMinutes(requestedEndEST.getMinutes() + 30);

// Convert to your local timezone (Africa/Lagos = UTC+1) for calendar query
const requestedStartWAT = new Date(requestedStartEST);
const requestedEndWAT = new Date(requestedEndEST);

// Format for display
const formattedEST = requestedStartEST.toLocaleString('en-US', {
  weekday: 'long',
  month: 'long',
  day: 'numeric',
  year: 'numeric',
  hour: 'numeric',
  minute: '2-digit',
  timeZone: 'America/New_York',
  hour12: true
});

const formattedWAT = requestedStartWAT.toLocaleString('en-US', {
  weekday: 'long',
  month: 'long',
  day: 'numeric',
  year: 'numeric',
  hour: 'numeric',
  minute: '2-digit',
  timeZone: 'Africa/Lagos',
  hour12: true
});

return [{
  json: {
    ...inputData,
    calendar_query: {
      start_utc: requestedStartEST.toISOString(),
      end_utc: requestedEndEST.toISOString(),
      start_est: formattedEST,
      start_wat: formattedWAT,
      timezone_lead: 'America/New_York',
      timezone_coach: 'Africa/Lagos'
    }
  }
}];

// Get the requested time from earlier in workflow
const extracted = $('Extract Date/Time').item.json.extracted;
const requestedDate = extracted.date;
const requestedTime = extracted.time;

// Get calendar events from previous node
const calendarEvents = $input.all();

// Create requested time slot
const requestedStart = new Date(requestedDate + 'T' + requestedTime + ':00');
const requestedEnd = new Date(requestedStart.getTime() + 30 * 60000); // 30 min duration

// Check for conflicts
let hasConflict = false;
let conflictingEvent = null;

for (const event of calendarEvents) {
  const eventData = event.json;

  // Skip if no start/end time
  if (!eventData.start || !eventData.end) continue;

  const eventStart = new Date(eventData.start.dateTime || eventData.start.date);
  const eventEnd = new Date(eventData.end.dateTime || eventData.end.date);

  // Check for overlap
  if (requestedStart < eventEnd && requestedEnd > eventStart) {
    hasConflict = true;
    conflictingEvent = {
      summary: eventData.summary,
      start: eventStart.toISOString(),
      end: eventEnd.toISOString()
    };
    break;
  }
}

// Get lead info from earlier nodes - with safe fallbacks
const filterReplies = $('Filter for replies').item.json;

// Safely extract email
const leadEmail = filterReplies.from || '';

// Safely extract name - handle the split() carefully
let leadName = '';
if (filterReplies.fromFull) {
  // Check if fromFull contains '<' before splitting
  if (filterReplies.fromFull.includes('<')) {
    leadName = filterReplies.fromFull.split('<')[0].trim();
  } else {
    leadName = filterReplies.fromFull.trim();
  }
} else {
  leadName = 'Valued Client'; // Fallback
}

const subject = filterReplies.subject || '';

// Return result
return [{
  json: {
    isAvailable: !hasConflict,
    hasConflict: hasConflict,
    conflictingEvent: conflictingEvent,
    requestedSlot: {
      start: requestedStart.toISOString(),
      end: requestedEnd.toISOString(),
      date: requestedDate,
      time: requestedTime
    },
    leadInfo: {
      email: leadEmail,
      name: leadName,
      subject: subject
    }
  }
}];

// Get the main folder data from "Build Folder Link" node
const mainFolder = $('Build Folder Link').item.json;
const mainFolderId = mainFolder.id;
const mainFolderLink = mainFolder.webViewLink;

// Define all subfolders to create
const subfolders = [
  { name: 'Session Notes', isAssessments: false },
  { name: 'Resources Shared', isAssessments: false },
  { name: 'Assessments & Results', isAssessments: true }, // ← Mark this one
  { name: 'Contracts & Agreements', isAssessments: false },
  { name: 'Invoices & Payment', isAssessments: false },
  { name: 'Action Plans & Goals', isAssessments: false }
];

// Return one item for each subfolder
return subfolders.map(folder => ({
  json: {
    folderName: folder.name,
    parentFolderId: mainFolderId,
    mainFolderLink: mainFolderLink,
    mainFolderId: mainFolderId,
    isAssessmentsFolder: folder.isAssessments // ← New flag
  }
}));

// Get folder data from previous nodes
const mainFolder = $('Build Folder Link').item.json;

// Get lead data from Airtable search
const airtableSearch = $('Search for Lead in Airtable').item.json;

// Try to get Assessments folder ID from the Store node
let assessmentsFolderId = null;
try {
  const assessmentsData = $('Store Assessments Folder ID').item.json;
  assessmentsFolderId = assessmentsData.assessmentsFolderId;
} catch (error) {
  // If node doesn't exist yet, leave as null
  console.log('Assessments folder ID not found');
}

// Handle both cases: when fields exist and when they don't
let leadEmail, leadName, scheduledDate, scheduledTime, calendarEventId;

if (airtableSearch.fields) {
  leadEmail = airtableSearch.fields.Email;
  leadName = airtableSearch.fields.Name;
  scheduledDate = airtableSearch.fields['Scheduled call date'];
  scheduledTime = airtableSearch.fields['Scheduled call time'];
  calendarEventId = airtableSearch.fields['Calendar event Id'];
} else {
  leadEmail = airtableSearch.Email;
  leadName = airtableSearch.Name;
  scheduledDate = airtableSearch['Scheduled call date'];
  scheduledTime = airtableSearch['Scheduled call time'];
  calendarEventId = airtableSearch['Calendar event Id'];
}

return [{
  json: {
    // Folder information
    folderId: mainFolder.id,
    folderLink: mainFolder.webViewLink,
    folderName: mainFolder.name,
    assessmentsFolderId: assessmentsFolderId, // ← NEW

    // Lead information for email
    Email: leadEmail,
    Name: leadName,
    'Scheduled call date': scheduledDate,
    'Scheduled call time': scheduledTime,
    'Calendar event Id': calendarEventId
  }
}];

// Get folder data from previous node
   const folderId = $input.item.json.id;
   const folderName = $input.item.json.name;

   // Google Drive folder URLs follow this pattern:
   // https://drive.google.com/drive/folders/{FOLDER_ID}
   const webViewLink = `https://drive.google.com/drive/folders/${folderId}`;

   return [{
     json: {
       id: folderId,
       name: folderName,
       webViewLink: webViewLink,
       mimeType: 'application/vnd.google-apps.folder'
     }
   }];

// 1. GET DATA (Corrected for your Workflow)
// ---------------------------------------------------------
const item = $input.item || $input.first();
const json = item.json || item;

// Data should now be in the "fields" property
const fields = json.fields || json;

// 2. MAP THE FIELDS (With Fallbacks)
// ---------------------------------------------------------
const leadName = fields["Name"] || fields["name"] || 'New Client';
const company = fields["Company"] || fields["company"] || 'Unknown Company';
const leadEmail = fields["Email"] || fields["email"] || 'no-email@example.com';
const leadScore = fields["Lead Score"] || 'N/A';
const challenge = fields["Challenge"] || 'Not specified';
const goal = fields["Goal"] || 'Not specified';
const driveFolderUrl = fields["Drive Folder URL"] || '';

// -- Parse the Call Date --
const dateStr = fields["Scheduled call date"];
const timeStr = fields["Scheduled call time"] || "12:00";

let callDate = new Date();
if (dateStr) {
    callDate = new Date(`${dateStr}T${timeStr}:00`);
}

// 3. CONFIGURATION (YOUR REAL IDS)
// ---------------------------------------------------------
const CLICKUP_LIST_ID = "901215691219";
const SARAH_USER_ID = 90126356128;

const CUSTOM_FIELD_IDS = {
    clientEmail: "74b86ab2-b755-45c6-bcbf-f9f0fa515cde",
    company: "34041b5d-6705-4467-84fd-2c074faee7a3",
    driveFolder: "53a5af00-0bab-40f3-b2df-e80fa2ef9ae8"
};

// 4. HELPER: Calculate Due Dates
// ---------------------------------------------------------
function calculateDueDate(baseDate, daysOffset) {
  const date = new Date(baseDate);
  date.setDate(date.getDate() + daysOffset);
  return date.getTime();
}

// 5. DEFINE THE TASKS
// ---------------------------------------------------------
const tasks = [
  {
    name: `1. Review Intake - ${leadName}`,
    description: `Review intake for ${leadName} (${company})\n\n**Lead Score:** ${leadScore}\n**Challenge:** ${challenge}\n**Goal:** ${goal}\n\n[Drive Folder](${driveFolderUrl})`,
    due_date: calculateDueDate(callDate, -2),
    priority: 2
  },
  {
    name: `2. Pre-Call Prep - ${leadName}`,
    description: `Prepare for call on ${dateStr || 'Today'} at ${timeStr}.\n\nChecklist:\n- [ ] Review notes\n- [ ] Research ${company} (${fields["Company Size"] || 'Unknown'} employees)\n- [ ] Review budget: ${fields["Budget Range"] || 'Unknown'}`,
    due_date: calculateDueDate(callDate, -1),
    priority: 1
  },
  {
    name: `3. Discovery Call - ${leadName}`,
    description: `Conduct call with ${leadName}\n\n**Phone:** ${fields.Phone || 'N/A'}\n**Title:** ${fields.Title || 'N/A'}\n**Folder:** [Drive](${driveFolderUrl})`,
    due_date: calculateDueDate(callDate, 0),
    priority: 1
  },
  {
    name: `4. Send Call Notes - ${leadName}`,
    description: `Summarize insights and send to ${leadEmail}.`,
    due_date: calculateDueDate(callDate, 1),
    priority: 2
  },
  {
    name: `5. Prepare Proposal - ${leadName}`,
    description: `Draft proposal based on goal: "${goal}".\nTimeline: ${fields.Timeline || 'Unknown'}`,
    due_date: calculateDueDate(callDate, 2),
    priority: 2
  },
  {
    name: `6. Send Proposal - ${leadName}`,
    description: `Send proposal to ${leadEmail}.`,
    due_date: calculateDueDate(callDate, 3),
    priority: 2
  },
  {
    name: `7. Follow-Up Call - ${leadName}`,
    description: `Check in regarding proposal sent on ${dateStr || 'Call Date'}.`,
    due_date: calculateDueDate(callDate, 6),
    priority: 3
  },
  {
    name: `8. Onboarding Setup - ${leadName}`,
    description: `Set up contract for ${company} if signed.`,
    due_date: calculateDueDate(callDate, 10),
    priority: 3
  }
];

// 6. RETURN DATA FOR CLICKUP
// ---------------------------------------------------------
return tasks.map(task => {
  return {
    json: {
      ...task,
      list_id: CLICKUP_LIST_ID,
      assignee_id: SARAH_USER_ID,
      cf_email_val: leadEmail,
      cf_company_val: company,
      cf_drive_val: driveFolderUrl,
      cf_email_id: CUSTOM_FIELD_IDS.clientEmail,
      cf_company_id: CUSTOM_FIELD_IDS.company,
      cf_drive_id: CUSTOM_FIELD_IDS.driveFolder
    }
  };
});

// Get the Airtable lead data
const airtableData = $('Search for Lead in Airtable').first().json;

// Get the folder link
const folderLink = $('Get Main Folder Link').first().json.folderLink;

// Check if data is in "fields" property or at root level
const leadFields = airtableData.fields || airtableData;

// Return ALL the lead data PLUS the folder URL
return [{
  json: {
    // Pass through the record ID
    id: airtableData.id,

    // Pass through ALL the Airtable fields for ClickUp to use
    fields: {
      ...leadFields,
      'Drive Folder URL': folderLink
    }
  }
}];

// Get the Airtable lead data
const airtableData = $('Search for Lead in Airtable').first().json;

// Get the folder link and assessments folder ID
const folderData = $('Get Main Folder Link').first().json;
const folderLink = folderData.folderLink;
const assessmentsFolderId = folderData.assessmentsFolderId;

// Check if data is in "fields" property or at root level
const leadFields = airtableData.fields || airtableData;

// Return ALL the lead data PLUS the folder URL and Assessments folder ID
return [{
  json: {
    // Pass through the record ID
    id: airtableData.id,

    // Pass through ALL the Airtable fields for ClickUp to use
    fields: {
      ...leadFields,
      'Drive Folder URL': folderLink,
      'Drive Folder ID': assessmentsFolderId // ← NEW
    }
  }
}];

